def _extend_unique(target: list[str], values: list[str]) -> None:
    for value in values:
        if isinstance(value, str) and value and (value not in target):
            target.append(value)

def _extend_shot_pool(target: dict[str, list[str]], additions: dict[str, list[str]]) -> None:
    for shot, values in additions.items():
        if shot in target and isinstance(target[shot], list):
            _extend_unique(target[shot], values)
        elif shot in target and isinstance(target[shot], dict):
            target[shot].setdefault('default', [])
            if isinstance(target[shot]['default'], list):
                _extend_unique(target[shot]['default'], values)

def _extend_scale_pool(target: dict[str, list[str]], additions: dict[str, list[str]]) -> None:
    for scale, values in additions.items():
        if scale in target and isinstance(target[scale], list):
            _extend_unique(target[scale], values)

def _extend_scale_shot_pool(target: dict[str, dict[str, list[str]]], additions: dict[str, dict[str, list[str]]]) -> None:
    for scale, shot_values in additions.items():
        if scale in target and isinstance(target[scale], dict):
            _extend_shot_pool(target[scale], shot_values)
