def _options_for_aspect(value, aspect: str='portrait') -> list[str]:
    if isinstance(value, list):
        return value
    if not isinstance(value, dict):
        return []
    aspect_options = value.get(aspect)
    if isinstance(aspect_options, list):
        return aspect_options
    portrait_options = value.get('portrait')
    if isinstance(portrait_options, list):
        return portrait_options
    for item in value.values():
        if isinstance(item, list):
            return item
        if isinstance(item, dict):
            nested = _options_for_aspect(item, aspect)
            if nested:
                return nested
    return []

def camera_options_by_aspect(shot: str, aspect: str) -> list[str]:
    if aspect == 'landscape' and shot in landscape_camera_options:
        return _options_for_aspect(landscape_camera_options[shot], aspect)
    return _options_for_aspect(CAMERA_OPTIONS[shot], aspect)

def character_identity_options_by_aspect(shot: str, aspect: str) -> list[str]:
    return _options_for_aspect(CHARACTER_IDENTITY_BY_SHOT[shot], aspect)

def _pool_scale(scale: str) -> str:
    return 'bold' if scale in {'bold_no_outfit', 'nsfw'} else scale

def _pose_pool_scale(scale: str) -> str:
    return 'bold' if scale == 'bold_no_outfit' else scale

def makeup_options_by_aspect(scale: str, aspect: str) -> list[str]:
    return _options_for_aspect(MAKEUP_OPTIONS[_pool_scale(scale)], aspect)

def _normalize_era(value: str) -> str:
    return ERA_ALIASES.get(str(value or '').strip(), 'modern')

def _filter_era_options(options: list[str], era: str, markers: tuple[str, ...]) -> list[str]:
    if not options:
        return options
    era = _normalize_era(era)
    if era == 'ancient':
        filtered = [item for item in options if any((marker in item for marker in markers))]
        return filtered
    else:
        filtered = [item for item in options if not any((marker in item for marker in markers))]
    return filtered or options

def outfit_options_by_aspect(scale: str, shot: str, aspect: str, era: str='modern') -> list[str]:
    ancient_options = globals().get('ANCIENT_OUTFIT_OPTIONS', {})
    era_key = _normalize_era(era)
    pool_key = _pool_scale(scale)
    if era_key == 'ancient' and pool_key in ancient_options and shot in ancient_options[pool_key]:
        return _options_for_aspect(ancient_options[pool_key][shot], aspect)
    options = _options_for_aspect(OUTFIT_OPTIONS[_pool_scale(scale)][shot], aspect)
    return _filter_era_options(options, era, ANCIENT_OUTFIT_MARKERS)
