def _normalize_pose_text(pose_text: str) -> str:
    brow_replacements = (
        ('从眉眼下方抬眸', '低头后抬眸'),
        ('从眉眼下方盯住镜头', '低头后盯住镜头'),
        ('从眉眼下方看向镜头', '低头后看向镜头'),
        ('从眉眼下方', '低头后'),
        ('眉心', '眼神'),
        ('眉头', '眼角'),
        ('眉间', '眼神'),
        ('额心', '额头'),
        ('额间', '额头'),
        ('印堂', '额头'),
        ('眉眼下方', '眼睛下方'),
        ('眉峰轻轻上扬', '眼神微微上挑'),
        ('眉峰上扬', '眼神微微上挑'),
        ('眉毛自然舒展', '眼神自然放松'),
        ('眉眼', '眼睛'),
    )
    for source, replacement in brow_replacements:
        pose_text = pose_text.replace(source, replacement)
    for source, replacement in _POSE_NORMALIZE_REPLACEMENTS:
        pose_text = pose_text.replace(source, replacement)
    return pose_text

def _normalize_pose_list(options: list[str]) -> list[str]:
    return [_normalize_pose_text(t) for t in options]

def pose_expression_options_by_aspect(scale: str, shot: str, aspect: str) -> list[str]:
    if scale == 'nsfw':
        return _normalize_pose_list(_options_for_aspect(POSE_EXPRESSION_OPTIONS['nsfw'][shot], aspect))
    if aspect == 'landscape':
        scale_options = landscape_pose_expression_options.get(_pose_pool_scale(scale), {})
        if shot in scale_options:
            return _normalize_pose_list(_options_for_aspect(scale_options[shot], aspect))
    return _normalize_pose_list(_options_for_aspect(POSE_EXPRESSION_OPTIONS[_pose_pool_scale(scale)][shot], aspect))

def scene_light_options_by_aspect(scale: str, shot: str, aspect: str, era: str='modern'):
    if scale in {'bold', 'bold_no_outfit', 'nsfw'}:
        if _normalize_era(era) == 'ancient':
            ancient_scene_options = globals().get('ANCIENT_SEDUCTIVE_SCENE_OPTIONS', {})
            if shot in ancient_scene_options:
                return _options_for_aspect(ancient_scene_options[shot], aspect)
        return _filter_era_options(list(_NO_OUTFIT_MIST_SCENE_OPTIONS[shot]), era, ANCIENT_SCENE_MARKERS)
    scene_scale = scale if scale in SCENE_LIGHT_OPTIONS else _pool_scale(scale)
    options = SCENE_LIGHT_OPTIONS[scene_scale][shot]
    if isinstance(options, dict) and any((key in options for key in ('室内', '室外', '野外', 'default'))):
        filtered_groups = {}
        for group, group_options in options.items():
            if group not in ('室内', '室外', '野外', 'default'):
                continue
            filtered = _filter_era_options(_options_for_aspect(group_options, aspect), era, ANCIENT_SCENE_MARKERS)
            if filtered:
                filtered_groups[group] = filtered
        return filtered_groups
    return _filter_era_options(_options_for_aspect(options, aspect), era, ANCIENT_SCENE_MARKERS)

def _load_generated_prompt_data() -> None:
    import os
    if os.environ.get('RPP_IGNORE_GENERATED_PROMPT_DATA') == '1':
        return
    try:
        import prompt_data_generated as generated
    except Exception:
        return
    names = ('QUALITY_SUFFIX', 'NEGATIVE_PROMPT', 'CAMERA_OPTIONS', 'CHARACTER_IDENTITY_BY_SHOT', 'MAKEUP_OPTIONS', 'OUTFIT_OPTIONS', 'POSE_EXPRESSION_OPTIONS', 'SCENE_LIGHT_OPTIONS', 'landscape_camera_options', 'landscape_pose_expression_options')
    for name in names:
        if hasattr(generated, name):
            globals()[name] = getattr(generated, name)
    globals()['PROMPT_DATA_SOURCE'] = 'prompt_data_generated.py'

def _load_nsfw_pose_expression_json() -> None:
    path = Path(__file__).resolve().parent / 'data' / 'nsfw_pose_expression_options.json'
    if not path.is_file():
        return
    try:
        data = json.loads(path.read_text(encoding='utf-8'))
    except Exception:
        return
    if not isinstance(data, dict):
        return
    required_shots = {'head_shot', 'half_body', 'full_body'}
    if not required_shots.issubset(data.keys()):
        return
    cleaned = {}
    for shot in required_shots:
        options = data.get(shot)
        if not isinstance(options, list):
            return
        cleaned[shot] = [str(item).strip() for item in options if str(item).strip()]
    POSE_EXPRESSION_OPTIONS['nsfw'] = cleaned
    globals()['NSFW_POSE_EXPRESSION_SOURCE'] = 'data/nsfw_pose_expression_options.json'

